INSERT INTO public.products VALUES ('74672055-c272-40e9-9a0a-033dc98793fe', 'Sunissime Anti-Aging Global Protection SPF50+', '8cebffaa-ef68-4369-a08e-ff9cd70b17e3', 'Sunscreen', 'Luxurious anti-aging sunscreen with advanced EU sun filters.', 'Anti-aging sun protection, mature skin needing SPF', 'EU sunscreen technology with French anti-aging expertise.', false, true, false, true, '/attached_assets/generated_images/lierac_sunscreen_tube.png');
INSERT INTO public.products VALUES ('9f94759b-a9d5-4cf8-be4a-bdde39a590fa', 'Vichy LiftActiv Supreme Anti-Aging Face Cream', 'be047683-8275-4206-837f-9fd9f455a557', 'Moisturizer', 'A powerful anti-aging day cream designed to visibly reduce wrinkles and firm the skin. Enriched with Vichy''s signature Mineralizing Thermal Water and anti-aging ingredients, it provides hydration and a lifting effect for smoother and more youthful-looking skin.', 'Ideal for women looking to target fine lines, wrinkles, and loss of firmness while keeping the skin hydrated and radiant.', 'The product is significantly cheaper in French pharmacies compared to US stores, often up to 30% less. Additionally, the packaging sizes in France can be larger, offering better value.', true, false, false, true, '/attached_assets/generated_images/vichy_liftactiv_cream_jar.png');
INSERT INTO public.products VALUES ('a0fcd0e8-0f51-4d51-ae9a-19609d56cae4', 'Avène PhysioLift Night Smoothing Regenerating Balm', '2399c263-bccb-4e12-bdef-d95f449ae372', 'Treatment', 'This anti-aging night balm works overnight to smooth the appearance of wrinkles, firm the skin, and restore radiance for a rested and rejuvenated look. Its unique formula is suitable even for sensitive skin.', 'Targeting fine lines, deep wrinkles, and loss of firmness, especially for those with sensitive or reactive skin.', 'This product is significantly cheaper in French pharmacies compared to US retailers, and larger sizes are often available.', true, false, false, true, '/attached_assets/generated_images/avène_physiolift_jar.png');
INSERT INTO public.products VALUES ('270bcfac-276a-464c-86c7-198e972e6247', 'Caudalie Resveratrol-Lift Firming Night Cream', '8e3a594a-b73c-44b5-8275-dad58a46ed75', 'Treatment', 'This luxurious anti-aging night cream is formulated to visibly firm, lift, and smooth the skin while you sleep. Powered by Caudalie''s patented Resveratrol technology, it works synergistically with hyaluronic acid and vegan collagen to restore skin''s elasticity and reduce the appearance of fine lines and wrinkles.', 'Ideal for women experiencing early to advanced signs of aging, including loss of firmness, fine lines, and a lack of hydration.', 'This product is significantly more affordable in French pharmacies compared to US retailers, often costing up to 30% less.', true, false, false, true, '/attached_assets/generated_images/caudalie_resveratrol_jar.png');
INSERT INTO public.products VALUES ('efe4666b-af5b-4f62-95eb-610a7bf59eaf', 'Lierac Premium Anti-Aging Absolute Cream', '8cebffaa-ef68-4369-a08e-ff9cd70b17e3', 'Moisturizer', 'A luxurious anti-aging face cream formulated with patented peptides and hyaluronic acid to target wrinkles, loss of firmness, and dullness. This rich cream deeply hydrates while addressing multiple signs of aging for a radiant, youthful complexion.', 'Women concerned with wrinkles, fine lines, and loss of elasticity, especially those looking for an all-in-one anti-aging treatment.', 'Lierac products are often priced significantly lower in France compared to US retailers. Additionally, some formulations may differ slightly in the EU, offering additional benefits.', true, false, false, true, '/attached_assets/generated_images/lierac_premium_cream_jar.png');
INSERT INTO public.products VALUES ('55579024-00c9-44e5-ad5f-c298fea2df50', 'Lotion Tonique Sans Alcool', '1dea8445-f3d0-4503-9737-72daffe5fb58', 'Toner', 'Alcohol-free toning lotion with orange blossom water. Refreshes and softens while preparing skin for the next steps.', 'All skin types, sensitive skin, dehydrated skin', 'French pharmacy heritage brand, exclusive large sizes', false, false, false, true, '/attached_assets/generated_images/nuxe_toner_bottle.png');
INSERT INTO public.products VALUES ('439be265-0c43-42ee-8599-865a4eb6ceaa', 'Topialyse Essence Hydratante', 'a85a20e0-f130-4c20-9c09-60aa21cbe365', 'Toner', 'Hydrating essence-toner hybrid that delivers instant moisture. Contains hyaluronic acid and niacinamide.', 'Dry skin, dehydrated skin, first step hydration', 'SVR formulas often have higher concentrations than US versions', false, true, false, false, '/attached_assets/generated_images/svr_topialyse_essence_bottle.png');
INSERT INTO public.products VALUES ('d34e9efc-7eea-434b-b3a3-b0c7b1195c08', 'Uriage Age Lift Smoothing Night Cream', '5f0ab354-d914-4632-b0ee-36881aff538a', 'Moisturizer', 'This anti-aging night cream works to smooth fine lines and wrinkles while firming the skin. Enriched with Uriage Thermal Water, it hydrates deeply and contains retinol-like actives for visible rejuvenation.', 'Ideal for women concerned with fine lines, wrinkles, and loss of firmness, who want a hydrating anti-aging cream for nighttime use.', 'This product is often more affordable in French pharmacies, with a price difference of 20-30% compared to US online retailers. Additionally, the formula includes EU-approved ingredients not always found in US products.', false, false, false, true, '/attached_assets/generated_images/uriage_age_lift_jar.png');
INSERT INTO public.products VALUES ('09b2aab0-251c-4447-bf97-e589da6544d9', 'La Roche-Posay Pigmentclar Eyes Brightening Eye Cream', 'ca37042e-8c7c-4e5f-8e51-e1e94b387385', 'Eye Care', 'A brightening eye cream designed to target dark circles and uneven pigmentation around the delicate eye area. Its gentle formula is suitable for sensitive skin and works to visibly improve eye contour radiance.', 'Ideal for those with dark circles, dullness, and signs of fatigue around the eyes.', 'This product is significantly cheaper in French pharmacies compared to the US, often by 30-40%. Additionally, larger sizes are more commonly available in France.', true, false, false, true, '/attached_assets/generated_images/la_roche-posay_eye_cream.png');
INSERT INTO public.products VALUES ('50a94ae3-dacc-47a4-b188-a42ecf27b355', 'Nuxe Nuxuriance Ultra Replenishing Rich Cream', '1dea8445-f3d0-4503-9737-72daffe5fb58', 'Moisturizer', 'A luxurious anti-aging cream that targets wrinkles, loss of firmness, and dullness while intensely moisturizing the skin. Formulated with saffron and bougainvillea bi-floral cells for effective skin rejuvenation.', 'Perfect for mature or dry skin types seeking hydration and anti-aging benefits such as reduced wrinkles and improved skin elasticity.', 'This product is significantly cheaper in French pharmacies compared to US retailers. Additionally, French pharmacies often carry larger sizes of Nuxe products, providing better value.', true, false, false, true, '/attached_assets/generated_images/nuxe_nuxuriance_jar.png');
INSERT INTO public.products VALUES ('ef9b08c6-1c23-4570-a892-7c4855dacfa0', 'Lotion Tonique Douceur', '8e3a594a-b73c-44b5-8275-dad58a46ed75', 'Toner', 'Gentle alcohol-free toner that refreshes and prepares skin for treatment. Contains grape extract for antioxidant protection.', 'All skin types, sensitive skin, toner step in skincare routine', 'Caudalie boutique exclusives and gift sets only in France, better prices', false, false, false, true, '/attached_assets/generated_images/caudalie_toner_bottle.png');
INSERT INTO public.products VALUES ('9bb2a657-bbe2-4966-91f2-373026797524', 'Elution Gentle Balancing Shampoo', 'a9955795-686a-4578-8813-4540e1811f8a', 'Hair Care', 'Dermatologist-developed shampoo that gently cleanses while maintaining scalp balance. Ideal for daily use on sensitive scalps.', 'Sensitive scalp, frequent washing, post-treatment hair care', 'French pharmacy exclusive formulas, larger professional sizes available', false, true, false, true, '/attached_assets/generated_images/ducray_elution_shampoo_bottle.png');
INSERT INTO public.products VALUES ('a4f04a7e-f291-41c7-95e0-950dce16ee84', 'La Roche-Posay Anthelios Dermo-Pediatrics Spray SPF50+', 'ca37042e-8c7c-4e5f-8e51-e1e94b387385', 'Sunscreen', 'A lightweight, high-protection spray sunscreen designed for both face and body, suitable for sensitive skin. It offers broad-spectrum UVA/UVB protection with EU-exclusive filters and is water-resistant, making it perfect for outdoor activities.', 'Ideal for all skin types, particularly sensitive skin or those seeking high sun protection for face and body. Great for families or travelers spending prolonged time outdoors.', 'This product includes advanced EU-only UV filters such as Mexoryl SX and Tinosorb S, which provide superior UVA protection compared to US formulations. It is also more affordable in French pharmacies compared to US prices.', true, true, false, true, '/attached_assets/generated_images/la_roche-posay_kids_sunscreen_spray.png');
INSERT INTO public.products VALUES ('75e84c4d-c1f9-426f-9edd-ef9c6f4eb690', 'Vichy Capital Soleil UV-Age Daily SPF50+', 'be047683-8275-4206-837f-9fd9f455a557', 'Sunscreen', 'A lightweight, daily anti-photoaging sunscreen with SPF50+ that combines high sun protection with anti-aging benefits. The formula is enriched with peptides and niacinamide to help prevent wrinkles and dark spots while protecting the skin from UV rays.', 'Ideal for daily use on face and body to protect against sun damage and prevent the signs of aging. Suitable for sensitive skin.', 'This sunscreen often costs significantly less in French pharmacies compared to US retailers, and it features advanced UV filters like Mexoryl XL, which are not available in the US.', true, true, false, true, '/attached_assets/generated_images/vichy_sunscreen_lotion_bottle.png');
INSERT INTO public.products VALUES ('b2c1cbb8-1b34-4d98-baa9-0430c2e61d89', 'Filorga Optim-Eyes Eye Contour Cream', 'c82df969-a916-45dd-ab88-9ac148305a8f', 'Eye Care', 'A multi-action eye cream that targets dark circles, puffiness, and fine lines with its advanced formula inspired by aesthetic medicine. It provides a refreshing texture that absorbs quickly, leaving the eye area revitalized.', 'Ideal for addressing dark circles, puffiness, and first signs of aging around the eyes, suitable for all skin types.', 'The price in French pharmacies is significantly lower compared to US online retailers, and the product is often available in exclusive packaging sizes in France.', true, false, false, true, '/attached_assets/generated_images/filorga_eye_contour_cream_jar.png');
INSERT INTO public.products VALUES ('82f07f7a-cd05-4dcc-8c12-d0ac7e279373', 'SVR Sun Secure Blur SPF50', 'a85a20e0-f130-4c20-9c09-60aa21cbe365', 'Sunscreen', 'SVR Sun Secure Blur SPF50 is a velvety sunscreen that offers broad-spectrum protection against UVA and UVB rays with a unique mousse-to-powder texture. It provides a blurring effect for a smooth, matte finish, ideal as a makeup base or standalone skin perfector.', 'Perfect for those looking for high sun protection with a matte finish, it is suitable for sensitive skin and helps to minimize the appearance of pores.', 'This sunscreen contains advanced EU-only UV filters like Tinosorb S and Uvinul A Plus, which are not available in US sunscreens. Additionally, it is often more affordable in France compared to international retail prices.', true, true, false, true, '/attached_assets/generated_images/svr_sunscreen_spf50_tube.png');
INSERT INTO public.products VALUES ('87eb2614-4461-4a47-bb04-4d07912925c2', 'Uriage Bariésun Ultra-Light Fluid SPF50+', '5f0ab354-d914-4632-b0ee-36881aff538a', 'Sunscreen', 'A lightweight, fast-absorbing sunscreen for face and body, offering high protection against UVA and UVB rays. Enriched with Uriage thermal water, it hydrates and soothes skin while being water-resistant and non-comedogenic.', 'Ideal for all skin types, including sensitive skin, and provides high sun protection without leaving a greasy residue.', 'This sunscreen is significantly cheaper in French pharmacies compared to US retailers, and it contains EU-approved UV filters for superior sun protection.', true, true, false, true, '/attached_assets/generated_images/uriage_sunscreen_bottle.png');
INSERT INTO public.products VALUES ('a41707a4-09af-4c5a-ae94-d70a674fa944', 'Caudalie Resveratrol-Lift Firming Eye Gel-Cream', '8e3a594a-b73c-44b5-8275-dad58a46ed75', 'Eye Care', 'This lightweight gel-cream is formulated to reduce puffiness, smooth fine lines, and firm the eye area, helping to restore a youthful appearance. Enriched with Caudalie''s patented Resveratrol and hyaluronic acid, it offers anti-aging benefits while hydrating delicate skin.', 'Ideal for those concerned with fine lines, wrinkles, puffiness, and loss of firmness around the eyes.', 'It is typically 25-30% cheaper in French pharmacies compared to US prices, making it a great deal for travelers.', true, false, false, true, '/attached_assets/generated_images/caudalie_eye_cream_jar.png');
INSERT INTO public.products VALUES ('e5bbe766-61d0-4923-a678-d40afcedd45f', 'La Roche-Posay Pure Vitamin C10 Serum', 'ca37042e-8c7c-4e5f-8e51-e1e94b387385', 'Serum', 'This potent yet lightweight serum combines pure vitamin C with salicylic acid and neurosensine to brighten skin, reduce fine lines, and improve overall texture. Its non-greasy formula is ideal for sensitive skin and delivers visible results over time.', 'Dull skin, uneven texture, fine lines, and sensitive skin types seeking a brightening and anti-aging boost.', 'The French price for this serum is significantly lower than its US retail price. Additionally, the formula contains a high concentration of pure vitamin C and is often fresher when purchased in France due to higher turnover rates.', true, false, false, true, '/attached_assets/generated_images/la_roche-posay_vitamin_c_serum.png');
INSERT INTO public.products VALUES ('f45b8222-ed06-4977-b5ba-d69b47dc32b4', 'Uriage Age Protect Multi-Action Eye Contour', '5f0ab354-d914-4632-b0ee-36881aff538a', 'Eye Care', 'This multi-action eye cream targets fine lines, puffiness, and dark circles while protecting the delicate eye area from environmental stressors like blue light and pollution. Its lightweight texture absorbs quickly, making it ideal for both day and night use.', 'Women concerned with aging signs around the eye area, dark circles, puffiness, and environmental protection.', 'This product is often priced significantly lower in French pharmacies compared to US retailers, and larger sizes are more commonly available in France.', false, false, false, true, '/attached_assets/generated_images/uriage_age_protect_eye.png');
INSERT INTO public.products VALUES ('03e5ccea-1ad6-4dcf-a7dd-1cb8df7ca3e1', 'SVR Densitium Contour des Yeux', 'a85a20e0-f130-4c20-9c09-60aa21cbe365', 'Eye Care', 'This advanced eye cream is specifically designed to target wrinkles, dark circles, puffiness, and loss of firmness around the delicate eye area. Formulated with anti-aging peptides and hyaluronic acid, it hydrates, plumps, and brightens for a refreshed and youthful appearance.', 'Addressing signs of aging, dark circles, puffiness, and loss of elasticity around the eyes.', 'SVR products are often more affordable in France, and this eye cream is usually priced significantly lower there compared to international retailers.', true, false, false, true, '/attached_assets/generated_images/svr_densitium_eye_tube.png');
INSERT INTO public.products VALUES ('76d54451-286d-4bf6-97d4-5cedb17c576f', 'Mela Bright Vitamin C Serum', '5f0ab354-d914-4632-b0ee-36881aff538a', 'Serum', 'A brightening and anti-aging serum formulated with stabilized Vitamin C and anti-pollution ingredients to restore radiance, reduce dark spots, and even out skin tone. It provides antioxidant protection while hydrating the skin for a luminous complexion.', 'Ideal for dull skin, dark spots, uneven skin tone, and early signs of aging.', 'This serum is significantly cheaper in French pharmacies compared to US pricing, offering great value for a high-quality, dermatologist-recommended product.', false, false, false, true, '/attached_assets/generated_images/uriage_vitamin_c_serum.png');
