INSERT INTO public.products VALUES ('c23ba109-035a-489a-8f94-ac7f4aef281f', 'Uriage Age Protect Multi-Action Intensive Serum', '5f0ab354-d914-4632-b0ee-36881aff538a', 'Serum', 'This multi-action serum combines pure stabilized Vitamin C with anti-aging peptides and Uriage Thermal Water to target wrinkles, pigmentation, and dullness. It protects skin from daily oxidative stress while boosting radiance and hydration.', 'Ideal for women looking to reduce fine lines, dark spots, and improve overall skin brightness and elasticity.', 'This serum is significantly more affordable in French pharmacies compared to its price in the US and features EU-approved stabilized Vitamin C formulations not commonly found in US products.', true, false, false, true, '/attached_assets/generated_images/uriage_age_serum_bottle.png');
