INSERT INTO public.products VALUES ('5804398f-f12c-4222-b808-3387d6d4ca11', 'Hydraphase Intense Serum', 'ca37042e-8c7c-4e5f-8e51-e1e94b387385', 'Serum', 'This ultra-light hydrating serum is formulated with hyaluronic acid and La Roche-Posay''s Thermal Spring Water to deliver deep and lasting hydration for dehydrated skin. Its non-sticky texture absorbs quickly for immediate comfort.', 'Ideal for dehydrated skin, sensitive skin, or anyone needing an extra boost of moisture.', 'It is often more affordable in French pharmacies compared to US prices, and larger sizes are available exclusively in France.', true, false, false, true, '/attached_assets/generated_images/lrp_hydraphase_serum.png');
INSERT INTO public.products VALUES ('248364c2-faad-4566-b392-8a27d8b6247d', 'Lierac Supra Radiance Double Peeling Radiance Serum', '8cebffaa-ef68-4369-a08e-ff9cd70b17e3', 'Serum', 'A brightening and resurfacing serum that combines exfoliating and antioxidant properties to reveal radiant, smooth skin. It targets dullness and signs of aging while promoting even skin tone.', 'Ideal for dull, uneven skin tone and early signs of aging, it helps improve radiance and smooth texture.', 'This product is typically priced much lower in French pharmacies compared to US retailers, and the formula is optimized under EU regulations for maximum effectiveness.', true, false, false, true, '/attached_assets/generated_images/lierac_radiance_serum_bottle.png');
INSERT INTO public.products VALUES ('1de2ad4c-2676-48cf-839c-afcdd6fbc72b', 'Melvita Pulpe de Rose Plumping Radiance Serum', '4860366a-61b7-4d6b-994b-06d13c61ad84', 'Serum', 'This lightweight serum combines the power of vitamin C with wild rose extract to boost skin radiance and smooth fine lines. Its gel-like texture absorbs quickly, leaving the skin hydrated and glowing.', 'Ideal for dull, tired skin that needs a boost of radiance and hydration. Helps reduce the appearance of fine lines and uneven skin tone.', 'Melvita products are typically more affordable in French pharmacies, and this serum is harder to find in the US. Buying in France ensures access to the original formula at a better price.', false, true, false, true, '/attached_assets/generated_images/melvita_rose_serum_bottle.png');
