INSERT INTO public.products VALUES ('320912fd-35a2-4cc6-8450-d996f7571429', 'Cicalfate+ Restorative Protective Cream', '2399c263-bccb-4e12-bdef-d95f449ae372', 'Treatment', 'Cult restorative cream that repairs and protects irritated, weakened skin. Contains copper-zinc complex.', 'Damaged skin barrier, irritations, post-procedure skin, family first-aid', 'Much cheaper at French pharmacies with dermatologist recommendations', true, false, true, true, '/attached_assets/generated_images/avène_cicalfate_cream_tube.png');
INSERT INTO public.products VALUES ('135a1bb9-a01a-4b05-8646-2f167ab16e9f', 'Anthelios UVMune 400 Invisible Fluid SPF50+', 'ca37042e-8c7c-4e5f-8e51-e1e94b387385', 'Sunscreen', 'Revolutionary sunscreen with Mexoryl 400 technology that protects against ultra-long UVA rays.', 'Superior sun protection with advanced UV filters not available in US formulations', 'Contains Mexoryl 400, the newest UV filter technology approved in Europe but not yet in the US.', true, true, false, true, '/attached_assets/generated_images/la_roche-posay_sunscreen_tube.png');
INSERT INTO public.products VALUES ('44c47aa6-f450-4b28-b40d-1f1a90124037', 'Nuxe Baume Lèvres Prodigieux', '1dea8445-f3d0-4503-9737-72daffe5fb58', 'Lip Care', 'The Nuxe Baume Lèvres Prodigieux is a nourishing and subtly tinted lip balm that combines hydration with a hint of natural color. Infused with botanical oils, this balm leaves lips feeling soft, smooth, and radiant.', 'Ideal for those looking to hydrate dry, chapped lips while adding a touch of natural color and shine.', 'This product is often priced more affordably in French pharmacies compared to US retailers and is sometimes harder to find stateside.', true, false, false, true, '/attached_assets/generated_images/nuxe_baume_levres_pot.png');
INSERT INTO public.products VALUES ('fdb0cf36-c360-4796-8800-fdf31bc94b36', 'Uriage Eau Thermale Water Serum', '5f0ab354-d914-4632-b0ee-36881aff538a', 'Serum', 'A lightweight hydrating serum that deeply replenishes moisture using Uriage''s thermal water, delivering long-lasting hydration while soothing sensitive skin. The silky formula absorbs quickly, leaving skin plump, smooth, and radiant.', 'Ideal for dehydrated, sensitive, or dry skin types in need of deep hydration and soothing care.', 'This serum is significantly cheaper in French pharmacies compared to US retailers, and the brand''s thermal water-rich formulas are iconic in France.', true, false, false, true, '/attached_assets/generated_images/uriage_thermal_water_spray.png');
INSERT INTO public.products VALUES ('2987267e-b821-47b5-8016-9de1b217fcc6', 'Filorga Nutri-Filler Lips Nutri-Plumping Lip Balm', 'c82df969-a916-45dd-ab88-9ac148305a8f', 'Lip Care', 'This luxurious lip balm combines deep nourishment, anti-aging care, and a plumping effect. It restores hydration, smooths fine lines, and enhances natural lip color, leaving lips fuller and healthier with a subtle glossy finish.', 'Perfect for dry, aging, or lackluster lips needing hydration, repair, and a youthful boost.', 'This product is significantly cheaper in France than in the US, with savings of up to 30%. Additionally, it''s a popular product that may not be as widely stocked in US stores.', true, false, false, true, '/attached_assets/generated_images/filorga_lip_plumping_balm.png');
INSERT INTO public.products VALUES ('c278082d-a49f-4140-8a8c-5e07875652e6', 'Hydraliane Intense Moisturizing Serum', 'a85a20e0-f130-4c20-9c09-60aa21cbe365', 'Serum', 'Hydraliane Intense Serum is a lightweight, fast-absorbing hydrating serum designed to provide deep hydration for dehydrated and sensitive skin. Formulated with 60% physio-adapted water, it mimics the skin''s natural hydration system for immediate and long-lasting moisture.', 'Ideal for dehydrated, sensitive, or dry skin in need of intense and immediate hydration. Perfect for layering under a moisturizer or as a standalone hydrating serum in humid climates.', 'SVR products are often priced significantly lower in France compared to US retailers. French pharmacies offer this serum at nearly half the price, and it is also more readily available in France.', true, false, false, true, '/attached_assets/generated_images/svr_hydraliane_serum.png');
