INSERT INTO public.products VALUES ('d62a3f2a-9ae3-4a5e-acef-2bf474b4b305', 'Pigmentbio Daily Care SPF50+', '3f6b360c-e2ab-4204-98a9-5dd9f73bc584', 'Moisturizer', 'Daily brightening moisturizer with high sun protection. Prevents and reduces dark spots.', 'Dark spots, sun spots, hyperpigmentation prevention, melasma', 'EU SPF50+ with advanced filters plus pharmacy dermatologist advice', false, true, false, false, '/attached_assets/generated_images/bioderma_pigmentbio_spf_tube.png');
INSERT INTO public.products VALUES ('7a182adc-3796-4733-9f48-ab8d8f52f0bc', 'Peptides Defence Serum', '98203ee4-b8f2-4254-861a-5462b99d8a51', 'Serum', 'Advanced peptide serum that stimulates collagen production. Visibly reduces fine lines and firms skin.', 'Fine lines, loss of firmness, early aging, prevention', 'Institut Esthederm spa-grade formulas at pharmacy prices', false, false, false, true, '/attached_assets/generated_images/esthederm_peptides_serum_dropper.png');
INSERT INTO public.products VALUES ('be26c45c-977d-4875-a922-c2a53742bf47', 'Redermic R Retinol Cream', 'ca37042e-8c7c-4e5f-8e51-e1e94b387385', 'Treatment', 'Pure retinol cream in progressive release formula. Reduces wrinkles while minimizing irritation.', 'Wrinkles, loss of firmness, uneven texture, anti-aging', 'EU retinol formulation with dermatologist guidance', false, false, false, true, '/attached_assets/generated_images/lrp_redermic_r_tube.png');
INSERT INTO public.products VALUES ('d2386b04-1c25-4fd5-ad39-938815365d58', 'NCEF-Reverse Supreme Multi-Correction Cream', 'c82df969-a916-45dd-ab88-9ac148305a8f', 'Moisturizer', 'Intensive anti-aging cream with 50 regenerating ingredients. Targets wrinkles, firmness, and radiance.', 'Deep wrinkles, loss of firmness, dull mature skin, global aging', 'Filorga medical aesthetic technology at 50% less than US prices', true, false, true, true, '/attached_assets/generated_images/filorga_ncef-reverse_cream_jar.png');
INSERT INTO public.products VALUES ('668cd6c5-45e6-456e-9b8f-787cc57ec47f', 'Time-Filler 5XP Correction Gel-Cream', 'c82df969-a916-45dd-ab88-9ac148305a8f', 'Moisturizer', 'Multi-correction wrinkle cream that targets all types of wrinkles. Gel-cream texture for all skin types.', 'Fine lines, deep wrinkles, expression lines, all skin types', 'Filorga French aesthetic medicine expertise, much cheaper', true, false, false, true, '/attached_assets/generated_images/filorga_time-filler_pump.png');
INSERT INTO public.products VALUES ('b91908c8-05d7-4c85-940e-1aa572dbb171', 'Filorga Time-Filler Absolute Wrinkle Correction Cream', 'c82df969-a916-45dd-ab88-9ac148305a8f', 'Treatment', 'A potent anti-aging cream inspired by aesthetic medicine techniques, designed to reduce the appearance of all types of wrinkles, including fine lines, deep wrinkles, and expression lines. Its rich texture delivers intense hydration while smoothing and plumping the skin.', 'Ideal for women looking to prevent and reduce visible signs of aging, including wrinkles, loss of firmness, and dehydration.', 'Filorga products are significantly cheaper in French pharmacies compared to US retailers, and this cream often comes in larger sizes or exclusive promo sets unavailable in the US.', true, false, false, true, '/attached_assets/generated_images/filorga_anti-aging_cream_jar.png');
INSERT INTO public.products VALUES ('b854051b-3bb3-4d9a-a241-fee6138c4415', 'Photo Reverse Pigment Control', '98203ee4-b8f2-4254-861a-5462b99d8a51', 'Serum', 'Advanced brightening serum that reverses sun damage and pigmentation. Pro-level formula from spa expertise.', 'Sun damage, wrinkles, dark spots, photo-aging', 'Institut Esthederm spa technology at pharmacy prices', false, false, false, true, '/attached_assets/generated_images/esthederm_photo_reverse_serum.png');
INSERT INTO public.products VALUES ('8e5ff7fb-c5b6-408f-a046-07b21c7b8ecf', 'Rêve de Miel Ultra-Nourishing Lip Balm', '1dea8445-f3d0-4503-9737-72daffe5fb58', 'Lip Care', 'A cult-favorite rich lip balm formulated with honey and botanical oils to deeply nourish and repair dry, chapped lips. Its matte, non-greasy finish makes it perfect for day or night use.', 'Ideal for dry, cracked, or sensitive lips, especially in cold or dry climates.', 'This lip balm is significantly cheaper in French pharmacies compared to US prices, and the formula remains unchanged from its French origin.', true, false, false, true, '/attached_assets/generated_images/nuxe_honey_lip_balm_jar.png');
INSERT INTO public.products VALUES ('afc8c428-c50e-4395-852a-49ef6852d3b9', 'Vichy Dercos Nutrients Detox Shampoo', 'be047683-8275-4206-837f-9fd9f455a557', 'Hair Care', 'This purifying shampoo is designed to detoxify hair and scalp from pollution and excess sebum. Formulated with spirulina extract and purifying charcoal, it leaves hair feeling fresh, light, and clean without stripping natural moisture.', 'Oily hair, pollution-exposed hair, and scalp prone to buildup or greasiness.', 'The price of this shampoo is significantly lower in French pharmacies compared to US retailers, and larger sizes are more easily available in France.', false, false, false, true, '/attached_assets/generated_images/vichy_dercos_shampoo.png');
INSERT INTO public.products VALUES ('d4f172a0-fad7-444b-8462-31bd51bfcbc5', 'Cicaplast Lips Barrier Repairing Balm', 'ca37042e-8c7c-4e5f-8e51-e1e94b387385', 'Lip Care', 'La Roche-Posay Cicaplast Lips is a soothing and repairing lip balm designed to restore and protect dry, chapped, or irritated lips. Enriched with Panthenol, Shea Butter, and MP-Lipids, it provides intense hydration while repairing the skin barrier.', 'Ideal for anyone with extremely dry, cracked lips or those prone to irritation caused by environmental factors such as cold weather or wind.', 'This product is significantly cheaper in French pharmacies compared to US retailers, offering better value for a trusted repair balm.', true, false, false, true, '/attached_assets/generated_images/lrp_cicaplast_lips_tube.png');
INSERT INTO public.products VALUES ('15a29241-c1cd-464e-9781-c133c54f5c59', 'Klorane Shampoo with Quinine and Edelweiss', '10ea18e0-9fab-4ecc-baa8-f436bef887e2', 'Hair Care', 'This strengthening shampoo is formulated with quinine extract and organic edelweiss to help invigorate hair from the roots, making it ideal for thinning or weakened hair. Its gentle cleansing base respects the scalp while boosting vitality and resilience.', 'Thinning hair, weakened strands, and those looking to promote stronger, healthier growth.', 'Significant price savings in French pharmacies compared to US retailers, and larger bottle sizes are sometimes available exclusively in France.', true, false, false, true, '/attached_assets/generated_images/klorane_quinine_shampoo.png');
INSERT INTO public.products VALUES ('d0414af8-de5b-482c-86fc-88ae5a1dab97', 'Bioderma Photoderm Max Aquafluide SPF50+', '3f6b360c-e2ab-4204-98a9-5dd9f73bc584', 'Sunscreen', 'A lightweight, ultra-fluid sunscreen with SPF50+ that offers high UVA/UVB protection while feeling weightless on the skin. Perfect for face and body use, it leaves a matte finish without any oily residue.', 'Ideal for all skin types, including sensitive and combination skin, seeking broad-spectrum sun protection with a non-greasy, matte texture.', 'The French formula includes advanced EU-only UV filters (like Tinosorb S) for superior sun protection, and it''s significantly cheaper in France compared to US retailers.', true, true, false, true, '/attached_assets/generated_images/bioderma_photoderm_sunscreen.png');
INSERT INTO public.products VALUES ('5b987635-f138-4541-b7b6-040d63cfc8ba', 'Phytolaque Botanical Hair Spray', 'f8f0614b-a9c7-42b7-a29f-0db4c23c2702', 'Hair Care', 'Natural-hold hairspray with plant-based polymers. Provides flexible hold without stiffness or residue.', 'All hair types needing light hold, natural styling, brushable finish', 'Plant-based French formulas unavailable in US, significantly lower prices', false, true, false, true, '/attached_assets/generated_images/phyto_hair_spray_can.png');
INSERT INTO public.products VALUES ('3e24d96f-aecb-4ad7-86c6-34b7cd179b56', 'Complexe 5 Stimulating Plant Concentrate', '6805811a-f18c-4381-8923-ea856599b6e2', 'Hair Care', 'Warming scalp treatment that stimulates microcirculation. Essential oils and vitamins promote healthy hair growth.', 'Thinning hair, weak hair, scalp health, hair growth support', 'Cult French product with exclusive salon-grade formulas, half the US price', true, false, false, true, '/attached_assets/generated_images/rene_furterer_complexe_5_bottle.png');
INSERT INTO public.products VALUES ('bcc2bf9e-e191-4cbe-85f3-c37a1a918ce8', 'Ducray Extra-Doux Dermoprotective Shampoo', 'a9955795-686a-4578-8813-4540e1811f8a', 'Hair Care', 'This gentle, dermoprotective shampoo is designed for frequent use by the entire family. Its soap-free formula respects the scalp''s natural balance while leaving hair soft, shiny, and easy to manage.', 'Ideal for sensitive scalps, frequent washing, and maintaining healthy, balanced hair.', 'Significantly cheaper in French pharmacies compared to US-based retailers and often available in large family-sized bottles not easily found in the US.', false, false, false, true, '/attached_assets/generated_images/ducray_gentle_shampoo_bottle.png');
INSERT INTO public.products VALUES ('3e4fa8ab-4a20-496d-9560-07d662693245', 'Lierac Dioptiride Wrinkle Correction Filling Cream', '8cebffaa-ef68-4369-a08e-ff9cd70b17e3', 'Eye Care', 'Lierac Dioptiride Wrinkle Correction Filling Cream is an anti-aging eye treatment designed to visibly reduce fine lines, wrinkles, and signs of fatigue in the delicate eye area. Its light texture absorbs quickly, leaving the skin around the eyes smoother, hydrated, and refreshed.', 'Ideal for addressing early signs of aging, such as crow''s feet, fine lines, and under-eye wrinkles, while also providing hydration and soothing benefits.', 'Lierac is a French pharmacy brand and its products are often priced significantly lower in France than in the US, making it a cost-effective purchase during your trip. Additionally, this specific product may be harder to find in US stores.', true, false, false, true, '/attached_assets/generated_images/lierac_eye_cream_jar.png');
INSERT INTO public.products VALUES ('385fa00a-9371-4e11-acc0-61c607b76656', 'SVR Densitium Creme Riche', 'a85a20e0-f130-4c20-9c09-60aa21cbe365', 'Moisturizer', 'A luxurious anti-aging face cream designed for mature and dry skin, enriched with ultra-restructuring ingredients to improve skin density, elasticity, and hydration. It combats wrinkles and sagging while deeply nourishing and restoring the skin barrier.', 'Ideal for women experiencing visible signs of aging, including loss of firmness, wrinkles, and dry skin. Particularly suitable for post-menopausal skin.', 'SVR Densitium Creme Riche is significantly cheaper in France, with prices almost 30% lower compared to US retailers. Additionally, certain online retailers in the US charge a premium for this authentic French pharmacy product.', true, false, false, true, '/attached_assets/generated_images/svr_densitium_cream_jar.png');
INSERT INTO public.products VALUES ('e0dbf869-a8e4-4de7-8e3d-90188ece2025', 'SVR Ampoule Anti-Ox [C20] Vitamin C Serum', 'a85a20e0-f130-4c20-9c09-60aa21cbe365', 'Serum', 'This high-potency serum contains 20% stabilized Vitamin C to brighten the skin, improve radiance, and reduce signs of aging. Its lightweight, fast-absorbing formula is perfect for all skin types, including sensitive skin.', 'Dullness, uneven skin tone, fine lines, and antioxidant protection for all skin types.', 'This serum is significantly more affordable in France, where it is priced lower than in the US. Additionally, the product is not widely available in US retailers.', true, false, false, true, '/attached_assets/generated_images/svr_vitamin_c_ampoule.png');
INSERT INTO public.products VALUES ('e19d91c0-764c-4663-9fc9-539f38b25c68', 'Avène PhysioLift Eyes', '2399c263-bccb-4e12-bdef-d95f449ae372', 'Eye Care', 'A targeted anti-aging eye cream that reduces the appearance of wrinkles, puffiness, and dark circles while smoothing and firming the delicate eye area. Formulated with Avène''s Thermal Spring Water for soothing hydration.', 'Ideal for women looking to address fine lines, puffiness, and dark circles around the eyes while maintaining hydration and comfort for sensitive skin.', 'In France, this product is often 20-30% less expensive than in the US, making it a great deal when purchased directly from French pharmacies.', true, false, false, true, '/attached_assets/generated_images/avene_eye_cream_tube.png');
INSERT INTO public.products VALUES ('628a97ac-86b9-4748-83e4-070dd0f29f9a', 'Kerium Anti-Hairloss Shampoo', 'ca37042e-8c7c-4e5f-8e51-e1e94b387385', 'Hair Care', 'La Roche-Posay Kerium Anti-Hairloss Shampoo is specially formulated to address hair thinning and hair loss while gently cleansing the scalp. Enriched with anti-hair loss ingredients, it promotes microcirculation and strengthens hair fibers for visibly fuller, healthier-looking hair.', 'Ideal for individuals experiencing hair thinning, hair loss, or a sensitive scalp.', 'This product is more affordable in France compared to US retailers and is often harder to find in the US. French pharmacies stock the original formula with a better price point.', true, false, false, true, '/attached_assets/generated_images/la_roche-posay_hair_shampoo.png');
INSERT INTO public.products VALUES ('da47ef56-5679-470c-8a7e-92fe7ba47ed3', 'Lotion Tonique Douceur', 'ca37042e-8c7c-4e5f-8e51-e1e94b387385', 'Toner', 'A gentle, alcohol-free toner that removes residual impurities while soothing and hydrating sensitive skin. Formulated with La Roche-Posay thermal spring water for ultimate comfort.', 'Sensitive skin, post-cleansing hydration, removing cleanser residue', 'Significantly cheaper in French pharmacies and available in larger sizes not sold in the US.', true, false, false, true, '/attached_assets/generated_images/la_roche-posay_toner_bottle.png');
INSERT INTO public.products VALUES ('34307267-df4b-4ca5-a900-0811ed5f5dc6', 'Eau Florale de Rose Bio', '1dea8445-f3d0-4503-9737-72daffe5fb58', 'Toner', 'A certified organic rose floral water that tones, refreshes, and prepares the skin for moisturizer. Gentle enough for all skin types including sensitive.', 'All skin types, refreshing, toning, preparation for skincare routine', 'Nuxe organic line is primarily sold in France with limited US availability, making it a perfect France-only find.', false, true, false, true, '/attached_assets/generated_images/nuxe_rose_floral_water_bottle.png');
INSERT INTO public.products VALUES ('8ec012f7-8706-4412-9517-19198fe0b874', 'Pureté Thermale Perfecting Toner', 'be047683-8275-4206-837f-9fd9f455a557', 'Toner', 'A hydrating and mattifying toner enriched with Vichy volcanic water. Tightens pores and leaves skin feeling fresh and balanced.', 'Normal to combination skin, pore tightening, mattifying, hydration', 'Vichy products are significantly cheaper in France, often 40% less than US prices.', true, false, false, true, '/attached_assets/generated_images/vichy_perfecting_toner_bottle.png');
INSERT INTO public.products VALUES ('cb73111b-2130-4ebc-9288-90bc8ca7fd8c', 'Toléderm Control Soothing Cream', '5f0ab354-d914-4632-b0ee-36881aff538a', 'Moisturizer', 'Uriage Toléderm Control Soothing Cream is a hypoallergenic moisturizer specifically formulated to calm and hydrate sensitive, reactive skin prone to redness and rosacea. Its lightweight, nourishing texture helps strengthen the skin barrier while reducing visible irritation.', 'Ideal for those with sensitive or reactive skin, including redness and rosacea-prone skin. Provides soothing hydration and relief from discomfort.', 'This product is often more affordable in French pharmacies compared to US retailers, and larger sizes are sometimes available exclusively in France.', false, false, false, true, '/attached_assets/generated_images/uriage_tolederm_tube.png');
INSERT INTO public.products VALUES ('8b523e8d-6a55-4937-abd4-c5c05bc5b8c9', 'Aqualia Thermal Rehydrating Serum', 'be047683-8275-4206-837f-9fd9f455a557', 'Serum', 'A lightweight hydrating serum formulated with 97% natural-origin ingredients to deliver intense hydration to dehydrated skin. Enriched with Vichy Mineralizing Thermal Water and hyaluronic acid, this serum locks in moisture and strengthens the skin barrier.', 'Ideal for dehydrated, sensitive, or dry skin seeking long-lasting hydration and a plumping effect.', 'Significant price savings and availability of larger sizes in French pharmacies compared to US retail.', true, false, false, true, '/attached_assets/generated_images/vichy_aqualia_serum_bottle.png');
INSERT INTO public.products VALUES ('7e33f45d-e6bd-426d-afa7-ebd9101bcf17', 'Galenic Diffuseur de Beauté', '0b80fe55-2e75-4da6-9c0f-a5c6e142abac', 'Serum', 'Radiance-boosting gel that gives instant glow and smooth texture.', 'Dull skin, pre-makeup prep, instant radiance', 'Galénic is a hidden French luxury brand at pharmacy prices.', false, true, false, true, '/attached_assets/generated_images/galenic_beauty_serum_bottle.png');
INSERT INTO public.products VALUES ('4baf2c41-df99-4304-a82e-fd7419b2b6ba', 'NCEF-Reverse Supreme Regenerating Cream', 'c82df969-a916-45dd-ab88-9ac148305a8f', 'Treatment', 'Intensive regenerating cream with NCEF and retinol for mature skin.', 'Deep wrinkles, loss of firmness, dull complexion', 'Premium anti-aging at 40% less than US retail.', false, false, false, true, '/attached_assets/generated_images/filorga_ncef_jar.png');
INSERT INTO public.products VALUES ('bd5ba6f6-02d5-4a61-b947-b44dace3a935', 'Klorane Shampoo with Nettle', '10ea18e0-9fab-4ecc-baa8-f436bef887e2', 'Hair Care', 'This purifying shampoo is specially formulated for oily hair to regulate sebum production and prolong the time between washes. Made with nettle extract, it gently cleanses while leaving hair light, fresh, and balanced.', 'Ideal for those with oily scalps or hair that tends to get greasy quickly, helping to control excess oil and maintain freshness.', 'This product is significantly cheaper in French pharmacies compared to US prices and is often available in larger sizes that are not distributed in the US.', true, false, false, true, '/attached_assets/generated_images/klorane_nettle_shampoo.png');
INSERT INTO public.products VALUES ('43373e0d-3629-436f-bd85-1794fdbee366', 'Bioderma Sensibio H2O Micellar Water', '3f6b360c-e2ab-4204-98a9-5dd9f73bc584', 'Cleanser', 'This cult-favorite micellar water gently cleanses and removes makeup while respecting the skin''s natural balance. Perfect for sensitive skin, it leaves the face feeling soft and refreshed without any need for rinsing.', 'Sensitive skin, makeup removal, gentle cleansing for all skin types', 'Significantly cheaper in France than in the US, with larger sizes available at a better value.', true, false, false, true, '/attached_assets/generated_images/bioderma_micellar_water_bottle.png');
INSERT INTO public.products VALUES ('24808c90-93e2-41c6-b1df-efb026a617d8', 'Caudalie Premier Cru The Cream', '8e3a594a-b73c-44b5-8275-dad58a46ed75', 'Moisturizer', 'An advanced anti-aging cream that targets all signs of aging, including wrinkles, loss of firmness, dark spots, and hydration. This luxurious cream is formulated with patented Vinergy® technology to enhance skin''s energy and boost the effectiveness of its active ingredients.', 'Ideal for mature skin or anyone looking to address wrinkles, fine lines, uneven skin tone, and loss of elasticity.', 'Significantly cheaper in France compared to US prices, plus often available in exclusive value sets in French pharmacies.', true, false, false, true, '/attached_assets/generated_images/caudalie_premier_cru_jar.png');
INSERT INTO public.products VALUES ('f5086c07-b016-400b-9679-db568ad3e822', 'Embryolisse Lait-Crème Concentré', '94b5edc5-ff74-4f1a-881b-c6a873ed0ce7', 'Moisturizer', 'A multi-purpose moisturizing cream that delivers hydration, soothes irritation, and primes the skin for makeup. Renowned for its rich yet non-greasy formula, it’s a favorite among makeup artists and skincare enthusiasts alike.', 'Ideal for all skin types, especially dry and sensitive skin. Perfect for use as a daily moisturizer, primer, or even a hydrating mask.', 'This cult classic is significantly cheaper in French pharmacies compared to US retailers, making it a must-buy for travelers.', true, false, false, true, '/attached_assets/generated_images/embryolisse_moisturizer_tube.png');
INSERT INTO public.products VALUES ('9c56dacf-2bfc-407d-9a5f-43d524506e19', 'Avène Very High Protection Lotion SPF50+', '2399c263-bccb-4e12-bdef-d95f449ae372', 'Sunscreen', 'A lightweight, water-resistant sunscreen formulated with advanced UVA and UVB filters to protect even the most sensitive skin. Enriched with Avène Thermal Spring Water, it soothes and calms while providing powerful sun protection for both face and body.', 'Ideal for sensitive skin, including those prone to redness or irritation, and provides broad-spectrum protection against harmful UV rays.', 'This product contains EU-approved UV filters like Tinosorb S, which are not FDA-approved in the US, offering enhanced sun protection. It is also significantly cheaper in French pharmacies compared to similar products available in the US.', true, true, false, true, '/attached_assets/generated_images/avene_spf50_sunscreen_tube.png');
INSERT INTO public.products VALUES ('b7727466-06e2-4352-b0c0-1a55ba52ae66', 'Vichy Liftactiv Vitamin C Brightening Skin Corrector', 'be047683-8275-4206-837f-9fd9f455a557', 'Serum', 'This concentrated serum combines 15% pure vitamin C with hyaluronic acid and other antioxidants to brighten skin, reduce the appearance of fine lines, and protect against environmental stressors. Its lightweight, fast-absorbing texture makes it ideal for all skin types.', 'Ideal for dull, tired-looking skin, uneven tone, and those seeking an antioxidant boost to fight aging and pollution damage.', 'Vichy products are generally more affordable in French pharmacies, and this serum is often priced significantly lower compared to US retailers. Additionally, French pharmacies frequently offer bundle deals or larger sizes not available elsewhere.', true, false, false, true, '/attached_assets/generated_images/vichy_liftactiv_serum_bottle.png');
INSERT INTO public.products VALUES ('4a36f671-742f-4c1f-9a77-37426a23c5c7', 'Lierac Rosilogie Persistent Redness Neutralizing Cream', '8cebffaa-ef68-4369-a08e-ff9cd70b17e3', 'Treatment', 'A targeted cream specifically formulated to address persistent redness and visible blood vessels associated with rosacea. It provides instant soothing and long-term reduction of redness through a combination of botanical and dermatological actives.', 'Soothing and reducing redness for sensitive or rosacea-prone skin. Ideal for reducing visible blood vessels and calming irritation.', 'This product is more affordable in French pharmacies compared to US retailers, and Lierac products can be difficult to find in the US in their original formulations.', true, false, false, true, '/attached_assets/generated_images/lierac_anti-redness_cream_tube.png');
INSERT INTO public.products VALUES ('0c887e92-5a90-41cd-b0d9-0a44ee6c111c', 'Mineral 89 Hyaluronic Acid Serum', 'be047683-8275-4206-837f-9fd9f455a557', 'Serum', 'Hydrating serum with 89% Vichy Volcanic Water and hyaluronic acid.', 'Daily hydration boost and skin barrier strengthening', 'The 50ml size is only available in Europe.', true, true, true, true, '/attached_assets/generated_images/vichy_mineral_89_serum_bottle.png');
INSERT INTO public.products VALUES ('f9aa2a67-a125-4093-b5c9-439484ed0bef', 'Vinopure Clear Skin Purifying Toner', '8e3a594a-b73c-44b5-8275-dad58a46ed75', 'Toner', 'A natural salicylic acid toner that helps purify pores, reduce blemishes, and mattify oily skin. Made with organic grape water and essential oils.', 'Oily and combination skin, reducing pores, controlling shine, preventing breakouts', 'Caudalie products are typically 30-40% cheaper in French pharmacies compared to US retail.', true, false, false, true, '/attached_assets/generated_images/caudalie_vinopure_toner_bottle.png');
INSERT INTO public.products VALUES ('a143c555-b0c9-4460-a68d-ae28767ddfa9', 'Avène Antirougeurs Fort Relief Concentrate', '2399c263-bccb-4e12-bdef-d95f449ae372', 'Treatment', 'A targeted treatment designed to reduce redness and calm discomfort associated with rosacea and sensitive skin. With its concentrated formula, it works to strengthen the skin''s barrier and provide long-lasting relief.', 'Ideal for individuals with rosacea, redness-prone skin, or sensitive skin seeking relief from irritation and visible redness.', 'This product is significantly cheaper in French pharmacies compared to US retail prices, and the formula contains EU-approved soothing ingredients that may not be as common in US formulations.', true, false, false, true, '/attached_assets/generated_images/avène_fort_concentrate_dropper.png');
INSERT INTO public.products VALUES ('9ce12adc-e781-4980-93dd-93286178a207', 'SVR Sensifine AR Creme', 'a85a20e0-f130-4c20-9c09-60aa21cbe365', 'Moisturizer', 'A soothing and anti-redness cream designed specifically for sensitive and rosacea-prone skin. It helps to calm irritation, reduce redness, and deeply hydrate without clogging pores.', 'Ideal for individuals with rosacea, redness-prone skin, or very sensitive and reactive skin types.', 'This product is significantly more affordable in French pharmacies compared to US retailers and features a formula that is highly regarded in Europe for its calming properties.', true, false, false, true, '/attached_assets/generated_images/svr_sensifine_ar_tube.png');
